import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.ToNumberPolicy;
import com.google.gson.ToNumberStrategy;
import com.google.gson.internal.bind.ObjectTypeAdapter;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Constructor;
import java.lang.reflect.Method;
import java.util.Deque;
import java.util.Map;

public class ObjectTypeAdapterTest {

    private ObjectTypeAdapter adapter;
    private Gson gson;
    private ToNumberStrategy toNumberStrategy;

    @BeforeEach
    public void setUp() throws Exception {
        gson = mock(Gson.class);
        toNumberStrategy = ToNumberPolicy.DOUBLE;
        Constructor<ObjectTypeAdapter> constructor = ObjectTypeAdapter.class.getDeclaredConstructor(Gson.class, ToNumberStrategy.class);
        constructor.setAccessible(true);
        adapter = constructor.newInstance(gson, toNumberStrategy);
    }

    @Test
    public void testRead_primitiveTerminal() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);
        when(in.hasNext()).thenReturn(false);
        when(in.peek()).thenReturn(JsonToken.STRING);
        // Mock readTerminal to return a terminal value by invoking private method via reflection
        Method readTerminal = ObjectTypeAdapter.class.getDeclaredMethod("readTerminal", JsonReader.class, JsonToken.class);
        readTerminal.setAccessible(true);
        Object terminalValue = readTerminal.invoke(adapter, in, JsonToken.STRING);

        // Spy adapter to mock tryBeginNesting to return null to force readTerminal path
        ObjectTypeAdapter spyAdapter = Mockito.spy(adapter);
        doReturn(null).when(spyAdapter).tryBeginNesting(in, JsonToken.STRING);

        Object result = spyAdapter.read(in);
        assertEquals(terminalValue, result);
    }

    @Test
    public void testRead_emptyArray() throws Exception {
        JsonReader in = mock(JsonReader.class);

        // Setup peek sequence: BEGIN_ARRAY, END_ARRAY
        when(in.peek())
                .thenReturn(JsonToken.BEGIN_ARRAY)  // initial peek
                .thenReturn(JsonToken.END_ARRAY);   // after hasNext false

        when(in.hasNext())
                .thenReturn(false); // no elements in array

        doNothing().when(in).endArray();

        // Spy adapter to mock tryBeginNesting to return new ArrayList on BEGIN_ARRAY
        ObjectTypeAdapter spyAdapter = Mockito.spy(adapter);
        doAnswer(invocation -> {
            JsonToken token = invocation.getArgument(1);
            if (token == JsonToken.BEGIN_ARRAY) {
                return new java.util.ArrayList<>();
            }
            return null;
        }).when(spyAdapter).tryBeginNesting(any(JsonReader.class), any(JsonToken.class));

        Object result = spyAdapter.read(in);
        assertTrue(result instanceof java.util.List);
        assertTrue(((java.util.List<?>) result).isEmpty());
        verify(in).endArray();
    }

    @Test
    public void testRead_emptyObject() throws Exception {
        JsonReader in = mock(JsonReader.class);

        // Setup peek sequence: BEGIN_OBJECT, END_OBJECT
        when(in.peek())
                .thenReturn(JsonToken.BEGIN_OBJECT)  // initial peek
                .thenReturn(JsonToken.END_OBJECT);   // after hasNext false

        when(in.hasNext())
                .thenReturn(false); // no entries in object

        doNothing().when(in).endObject();

        // Spy adapter to mock tryBeginNesting to return new LinkedTreeMap on BEGIN_OBJECT
        ObjectTypeAdapter spyAdapter = Mockito.spy(adapter);
        doAnswer(invocation -> {
            JsonToken token = invocation.getArgument(1);
            if (token == JsonToken.BEGIN_OBJECT) {
                return new com.google.gson.internal.LinkedTreeMap<String, Object>();
            }
            return null;
        }).when(spyAdapter).tryBeginNesting(any(JsonReader.class), any(JsonToken.class));

        Object result = spyAdapter.read(in);
        assertTrue(result instanceof Map);
        assertTrue(((Map<?, ?>) result).isEmpty());
        verify(in).endObject();
    }

    @Test
    public void testRead_nestedStructures() throws Exception {
        JsonReader in = mock(JsonReader.class);

        // Setup sequence of peek() calls to simulate:
        // {
        //   "key1": [ "value1", "value2" ],
        //   "key2": "value3"
        // }

        // Sequence of peek calls:
        // initial: BEGIN_OBJECT
        // hasNext: true (for "key1")
        // peek after nextName: BEGIN_ARRAY
        // hasNext in array: true, true, false
        // peek in array: STRING, STRING, (end)
        // hasNext after array: true (for "key2")
        // peek after nextName: STRING
        // hasNext after: false

        when(in.peek())
                .thenReturn(JsonToken.BEGIN_OBJECT) // initial peek
                // first iteration in object
                .thenReturn(JsonToken.BEGIN_ARRAY) // peek after nextName "key1"
                // iterations in array
                .thenReturn(JsonToken.STRING) // first element in array
                .thenReturn(JsonToken.STRING) // second element in array
                .thenReturn(JsonToken.END_ARRAY) // end array
                // second iteration in object
                .thenReturn(JsonToken.STRING) // peek after nextName "key2"
                .thenReturn(JsonToken.END_OBJECT); // end object

        when(in.hasNext())
                .thenReturn(true) // for first key in object
                .thenReturn(true) // first element in array
                .thenReturn(true) // second element in array
                .thenReturn(false) // end array
                .thenReturn(true) // second key in object
                .thenReturn(false); // end object

        when(in.nextName())
                .thenReturn("key1")
                .thenReturn("key2");

        // Mock endArray and endObject calls
        doNothing().when(in).endArray();
        doNothing().when(in).endObject();

        // Spy adapter to handle tryBeginNesting:
        // BEGIN_OBJECT -> LinkedTreeMap
        // BEGIN_ARRAY -> ArrayList
        ObjectTypeAdapter spyAdapter = Mockito.spy(adapter);
        doAnswer(invocation -> {
            JsonToken token = invocation.getArgument(1);
            if (token == JsonToken.BEGIN_OBJECT) {
                return new com.google.gson.internal.LinkedTreeMap<String, Object>();
            } else if (token == JsonToken.BEGIN_ARRAY) {
                return new java.util.ArrayList<>();
            }
            return null;
        }).when(spyAdapter).tryBeginNesting(any(JsonReader.class), any(JsonToken.class));

        // Spy readTerminal to return string values for STRING tokens
        doAnswer(invocation -> {
            JsonToken token = invocation.getArgument(1);
            if (token == JsonToken.STRING) {
                // Return a dummy string value based on call count
                return "value" + System.nanoTime();
            }
            return null;
        }).when(spyAdapter).readTerminal(any(JsonReader.class), any(JsonToken.class));

        Object result = spyAdapter.read(in);

        assertTrue(result instanceof Map);
        Map<?, ?> map = (Map<?, ?>) result;

        assertTrue(map.containsKey("key1"));
        assertTrue(map.get("key1") instanceof java.util.List);
        java.util.List<?> list = (java.util.List<?>) map.get("key1");
        assertEquals(2, list.size());

        assertTrue(map.containsKey("key2"));
        assertTrue(map.get("key2") instanceof String);

        verify(in, times(1)).endArray();
        verify(in, times(1)).endObject();
    }
}
